const updateExperiment = `-- name: UpdateExperiment :one
UPDATE experiment SET
  course_id = $1,
  template_ref = $2,
  template_version = $3,
  name = $4,
  description = $5,
  components = $6,
  collab_mode = $7,
  group_config = $8,
  require_report = $9,
  wizard_step = $10
WHERE id = $11 AND deleted_at IS NULL
RETURNING id, tenant_id, course_id, author_id, template_ref, template_version, name, description, components, collab_mode, group_config, require_report, wizard_step, status, deleted_at, created_at, updated_at
`

type UpdateExperimentParams struct {
	CourseID        pgtype.Int8 `json:"course_id"`
	TemplateRef     pgtype.Text `json:"template_ref"`
	TemplateVersion pgtype.Text `json:"template_version"`
	Name            string      `json:"name"`
	Description     string      `json:"description"`
	Components      []byte      `json:"components"`
	CollabMode      int16       `json:"collab_mode"`
	GroupConfig     []byte      `json:"group_config"`
	RequireReport   bool        `json:"require_report"`
	WizardStep      int16       `json:"wizard_step"`
	ID              int64       `json:"id"`
}

func (q *Queries) UpdateExperiment(ctx context.Context, arg UpdateExperimentParams) (Experiment, error) {
	row := q.db.QueryRow(ctx, updateExperiment,
		arg.CourseID,
		arg.TemplateRef,
		arg.TemplateVersion,
		arg.Name,
		arg.Description,
		arg.Components,
		arg.CollabMode,
		arg.GroupConfig,
		arg.RequireReport,
		arg.WizardStep,
		arg.ID,
	)
	var i Experiment
	err := row.Scan(
		&i.ID,
		&i.TenantID,
		&i.CourseID,
		&i.AuthorID,
		&i.TemplateRef,
		&i.TemplateVersion,
		&i.Name,
		&i.Description,
		&i.Components,
		&i.CollabMode,
		&i.GroupConfig,
		&i.RequireReport,
		&i.WizardStep,
		&i.Status,
		&i.DeletedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

