const upsertCheckpointResult = `-- name: UpsertCheckpointResult :one
INSERT INTO checkpoint_result (id, tenant_id, instance_id, checkpoint_id, judge_task_ref, passed, score, detail_ref)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
ON CONFLICT (tenant_id, instance_id, checkpoint_id) DO UPDATE SET
  judge_task_ref = EXCLUDED.judge_task_ref,
  passed = EXCLUDED.passed,
  score = EXCLUDED.score,
  detail_ref = EXCLUDED.detail_ref,
  judged_at = now()
RETURNING id, tenant_id, instance_id, checkpoint_id, judge_task_ref, passed, score, detail_ref, judged_at
`

type UpsertCheckpointResultParams struct {
	ID           int64          `json:"id"`
	TenantID     int64          `json:"tenant_id"`
	InstanceID   int64          `json:"instance_id"`
	CheckpointID string         `json:"checkpoint_id"`
	JudgeTaskRef pgtype.Text    `json:"judge_task_ref"`
	Passed       bool           `json:"passed"`
	Score        pgtype.Numeric `json:"score"`
	DetailRef    pgtype.Text    `json:"detail_ref"`
}

func (q *Queries) UpsertCheckpointResult(ctx context.Context, arg UpsertCheckpointResultParams) (CheckpointResult, error) {
	row := q.db.QueryRow(ctx, upsertCheckpointResult,
		arg.ID,
		arg.TenantID,
		arg.InstanceID,
		arg.CheckpointID,
		arg.JudgeTaskRef,
		arg.Passed,
		arg.Score,
		arg.DetailRef,
	)
	var i CheckpointResult
	err := row.Scan(
		&i.ID,
		&i.TenantID,
		&i.InstanceID,
		&i.CheckpointID,
		&i.JudgeTaskRef,
		&i.Passed,
		&i.Score,
		&i.DetailRef,
		&i.JudgedAt,
	)
	return i, err
}
